  "decisionTree": {
    "start": "aspect",
    "steps": {
      "aspect": {
        "q": "What part of a loan origination are you trying to model?",
        "a": [
          {
            "label": "The loan / mortgage instrument",
            "next": "instrument"
          },
          {
            "label": "A party or role (borrower, lender, guarantor…)",
            "next": "party"
          },
          {
            "label": "Underwriting & risk",
            "why": "Credit risk assessment determines the likelihood a borrower repays — the core of underwriting.",
            "rec": "LOAN__LoansGeneral__LoanApplications__CreditRiskAssessment"
          },
          {
            "label": "Regulatory reporting (US HMDA)",
            "why": "The HMDA report satisfies US Home Mortgage Disclosure Act reporting for covered loans.",
            "rec": "LOAN__RealEstateLoans__HomeMortgageDisclosureActCoveredMortgages__HMDA-Report"
          }
        ]
      },
      "instrument": {
        "q": "Is the loan secured by real property?",
        "a": [
          {
            "label": "Yes — a residential mortgage",
            "why": "A mortgage grants a financial interest in real property to a non-owner, recorded by a registration authority.",
            "rec": "LOAN__RealEstateLoans__Mortgages__Mortgage"
          },
          {
            "label": "Yes — a revolving line against home equity",
            "why": "A HELOC is a line of credit secured by the equity in the borrower’s home.",
            "rec": "LOAN__LoansSpecific__ConsumerLoans__HomeEquityLineOfCredit"
          },
          {
            "label": "No — a general loan",
            "why": "Loan is the base debt instrument: money/credit extended to be repaid per contract terms.",
            "rec": "LOAN__LoansGeneral__Loans__Loan"
          }
        ]
      },
      "party": {
        "q": "Which side of the agreement?",
        "a": [
          {
            "label": "The party that repays",
            "why": "The borrower is obligated to repay principal with interest under the credit agreement.",
            "rec": "FBC__DebtAndEquities__Debt__Borrower"
          },
          {
            "label": "The party that extends credit",
            "why": "The lender extends credit expecting repayment with interest.",
            "rec": "FBC__DebtAndEquities__Debt__Lender"
          },
          {
            "label": "A third party guaranteeing the obligation",
            "why": "A guarantor provides indemnity for the obligation on behalf of the borrower.",
            "rec": "FBC__DebtAndEquities__Guaranty__Guarantor"
          }
        ]
      }
    }
  },
